import{_ as e,c as t,o as i,b as a}from"./app.517b8ad5.js";const u=JSON.parse('{"title":"HTTP","description":"","frontmatter":{"layout":"doc","title":"HTTP"},"headers":[{"level":2,"title":"GET 和 POST 的请求的区别","slug":"get-和-post-的请求的区别","link":"#get-和-post-的请求的区别","children":[]},{"level":2,"title":"在地址栏里输入一个地址回车会发生哪些事情","slug":"在地址栏里输入一个地址回车会发生哪些事情","link":"#在地址栏里输入一个地址回车会发生哪些事情","children":[]},{"level":2,"title":"HTTP 中的强缓存与协商缓存","slug":"http-中的强缓存与协商缓存","link":"#http-中的强缓存与协商缓存","children":[]}],"relativePath":"interview/http.md"}'),h={name:"interview/http.md"},l=a('<h1 id="http-相关基础" tabindex="-1">HTTP 相关基础 <a class="header-anchor" href="#http-相关基础" aria-hidden="true">#</a></h1><h2 id="get-和-post-的请求的区别" tabindex="-1">GET 和 POST 的请求的区别 <a class="header-anchor" href="#get-和-post-的请求的区别" aria-hidden="true">#</a></h2><ul><li>浏览器一般会对 Get 请求缓存，但很少对 Post 请求缓存</li><li>Get 通过查询字符串传参，Post 通过请求体传参</li><li>get 参数只允许 ASCII 字符，post 的参数传递支持更多的数据类型(如文件、图片)</li></ul><h2 id="在地址栏里输入一个地址回车会发生哪些事情" tabindex="-1">在地址栏里输入一个地址回车会发生哪些事情 <a class="header-anchor" href="#在地址栏里输入一个地址回车会发生哪些事情" aria-hidden="true">#</a></h2><ul><li>解析 URL： 首先会对 URL 进行解析，分析所需要使用的传输协议和请求的资源的路径</li><li>缓存判断： 浏览器会判断所请求的资源是否在缓存里</li><li>DNS 解析： 下一步首先需要获取的是输入的 URL 中的域名的 IP 地址，首先会判断本地是否有该域名的 IP 地址的缓存，如果有则使用，如果没有则向本地 DNS 服务器发起请求。</li><li>TCP 三次握手： ，确认客户端与服务器的接收与发送能力</li><li>HTTPS 握手： 如果使用的是 HTTPS 协议，在通信前还存在 TLS 的一个四次握手的过程。</li><li>返回数据： 当页面请求发送到服务器端后，服务器端会返回一个 html 文件作为响应，浏览器接收到响应后，开始对 html 文件进行解析，开始页面的渲染过程。</li><li>页面渲染</li><li>TCP 四次挥手： 最后一步是 TCP 断开连接的四次挥手过程。</li></ul><h2 id="http-中的强缓存与协商缓存" tabindex="-1">HTTP 中的强缓存与协商缓存 <a class="header-anchor" href="#http-中的强缓存与协商缓存" aria-hidden="true">#</a></h2><h4 id="强缓存分为expires-http1-0-规范-、-cache-control-http1-1-规范-两种。" tabindex="-1">强缓存分为<code>expires</code>（http1.0 规范）、 <code>cache-control</code>（http1.1 规范）两种。 <a class="header-anchor" href="#强缓存分为expires-http1-0-规范-、-cache-control-http1-1-规范-两种。" aria-hidden="true">#</a></h4><p>expires 是根据本地时间来判断的，假设客户端和服务器时间不同，会导致缓存命中误差</p><p>在 http1.1 规范中，提出了<code>cache-control</code>字段，且这个字段优先级高于上面提到的<code>Expires</code>，值是相对时间。</p><h4 id="协商缓存" tabindex="-1">协商缓存 <a class="header-anchor" href="#协商缓存" aria-hidden="true">#</a></h4><p>协商缓存（也叫对比缓存）是由服务器来确定资源是否可用.</p>',11),r=[l];function c(d,o,n,s,p,T){return i(),t("div",null,r)}const P=e(h,[["render",c]]);export{u as __pageData,P as default};
